import React, { useState, useEffect } from 'react';
import { Combobox } from '@salutejs/plasma-web';
export function App() {
    const flatItems = [
        {
            value: 'north_america',
            label: 'Северная Америка',
        },
        {
            value: 'rio_de_janeiro',
            label: 'Рио-де-Жанейро',
        },
        {
            value: 'sao_paulo',
            label: 'Сан-Паулу',
        },
        {
            value: 'buenos_aires',
            label: 'Буэнос-Айрес',
        },
        {
            value: 'cordoba',
            label: 'Кордова',
        },
        {
            value: 'bogota',
            label: 'Богота',
        },
        {
            value: 'medellin',
            label: 'Медельин',
        },
    ];
    const [value, setValue] = useState([]);
    const [checked, setChecked] = useState(false);
    const [indeterminate, setIndeterminate] = useState(false);
    const handleClick = () => {
        if (checked && !indeterminate) {
            setValue([]);
        } else {
            setValue(flatItems.map((item) => item.value));
        }
    };
    useEffect(() => {
        if (value.length === 0) {
            setChecked(false);
            setIndeterminate(false);
        } else if (value.length === flatItems.length) {
            setChecked(true);
            setIndeterminate(false);
        } else {
            setChecked(true);
            setIndeterminate(true);
        }
    }, [value]);
    return (
        <div style={{ display: "block", width: "300px", height: "300px" }}>
            <Combobox
                value={value}
                onChange={setValue}
                label="Label"
                placeholder="Placeholder"
                items={flatItems}
                multiple
                selectAllOptions={{
                    checked,
                    indeterminate,
                    onClick: handleClick,
                }}
                listOverflow="auto"
                listMaxHeight="200px"
            />
        </div>
    );
}

